mapper.select:
SELECT movie_id, name, cover, douban_score, year, regions, genres
FROM movies



        AND movie_id IN (
            SELECT keyword_pool.movie_id
            FROM (
                SELECT candidate.movie_id
                FROM (
                    SELECT
                        m.movie_id,
                        GREATEST(
                            similarity(COALESCE(m.name, ''), #{keyword}),
                            similarity(COALESCE(m.alias, ''), #{keyword}),
                            similarity(COALESCE(m.full_search_text, ''), #{keyword})
                        ) AS relevance
                    FROM movies m
                    WHERE m.full_search_text % #{keyword}
                       OR m.name % #{keyword}
                       OR m.alias % #{keyword}
                    ORDER BY relevance DESC
                    LIMIT 5000
                ) candidate

                UNION ALL

                SELECT fallback.movie_id
                FROM (
                    SELECT m.movie_id
                    FROM movies m
                    WHERE NOT EXISTS (
                        SELECT 1
                        FROM movies t
                        WHERE t.full_search_text % #{keyword}
                           OR t.name % #{keyword}
                           OR t.alias % #{keyword}
                    )
                      AND m.full_search_text ILIKE '%' || #{keyword} || '%'
                    LIMIT 5000
                ) fallback
            ) keyword_pool
        )



        AND EXISTS (
        SELECT 1
        FROM movie_genre_relation mgr
        INNER JOIN genres g ON mgr.genre_id = g.id
        WHERE mgr.movie_id = movies.movie_id
        AND g.name IN

            #{genre}

        )



        AND douban_score >= #{minScore}


        AND douban_score <= #{maxScore}



        AND year = #{year}


        AND year >= #{startYear}


        AND year <= #{endYear}



        AND EXISTS (
        SELECT 1
        FROM movie_region_relation mrr
        INNER JOIN regions r ON mrr.region_id = r.id
        WHERE mrr.movie_id = movies.movie_id
        AND r.name IN

            #{region}

        )



        AND (

            (directors @> jsonb_build_array(jsonb_build_object('name', #{director})))

        )



        AND (

            (actors @> jsonb_build_array(jsonb_build_object('name', #{actor})))

        )





        ORDER BY douban_score ${sortOrder}


        ORDER BY year ${sortOrder}


        ORDER BY douban_votes ${sortOrder}


        ORDER BY
        GREATEST(
            similarity(COALESCE(name, ''), #{keyword}),
            similarity(COALESCE(alias, ''), #{keyword}),
            similarity(COALESCE(full_search_text, ''), #{keyword})
        ) DESC,
        douban_score DESC,
        douban_votes DESC


        ORDER BY douban_score DESC

SELECT movie_id, name, cover, douban_score, year, regions, genres
FROM movies


        AND EXISTS (
        SELECT 1 FROM movie_genre_relation mgr
        INNER JOIN genres g ON mgr.genre_id = g.id
        WHERE mgr.movie_id = movies.movie_id
        AND g.name IN

            #{genre}

        )



        AND EXISTS (
        SELECT 1 FROM movie_region_relation mrr
        INNER JOIN regions r ON mrr.region_id = r.id
        WHERE mrr.movie_id = movies.movie_id
        AND r.name IN

            #{region}

        )



        AND EXISTS (
        SELECT 1 FROM movie_language_relation mlr
        INNER JOIN languages l ON mlr.language_id = l.id
        WHERE mlr.movie_id = movies.movie_id
        AND l.name IN

            #{language}

        )



        AND douban_score >= #{minScore}


        AND douban_score <= #{maxScore}



        AND year >= #{startYear}


        AND year <= #{endYear}





        ORDER BY douban_score ${sortOrder}, movie_id DESC


        ORDER BY year ${sortOrder}, movie_id DESC


        ORDER BY douban_votes ${sortOrder}, movie_id DESC


        ORDER BY year DESC, douban_score DESC, movie_id DESC

