UPDATE movies
name = #{name}, alias = #{alias}, actors = #{actors,typeHandler=com.movie.backend.config.JsonTypeHandler}, cover = #{cover}, directors = #{directors,typeHandler=com.movie.backend.config.JsonTypeHandler}, douban_score = #{doubanScore}, score = #{score}, douban_votes = #{doubanVotes}, votes = #{votes}, genres = #{genres}, imdb_id = #{imdbId}, languages = #{languages}, mins = #{mins}, regions = #{regions}, release_date = #{releaseDate}, storyline = #{storyline}, year = #{year}, writers = #{writers,typeHandler=com.movie.backend.config.JsonTypeHandler},
WHERE movie_id = #{id}

